const data = $input.first().json;

return [
  { json: { name: "maeve", token: data.maeveToken, delay: data.sheetDelay } },
  { json: { name: "elara",token: data.elaraToken, delay: data.sheetDelay } },
  { json: { name: "amara", token: data.amaraToken, delay: data.sheetDelay } },
];

// Mode: Run Once for All Items
const mediaItems = $input.all();
const tokenList  = $items("packTokens");

// Build profiles lookup by first name
const profiles = {};
for (const p of $('getProfiles').all()) {
  const key = p.json.name.trim().split(/\s+/)[0].toLowerCase();
  profiles[key] = p.json;
}

const result = [];
for (let i = 0; i < mediaItems.length; i++) {
  const ctx      = tokenList[i].json;
  const profile  = profiles[ctx.name];
  const mediaArray = mediaItems[i].json.data;

  for (const media of mediaArray) {
    result.push({
      json: {
        ...media,
        name:            ctx.name,
        token:           ctx.token,
        delay:           ctx.delay,
        followers_count: profile?.followers_count ?? null,
        follows_count:   profile?.follows_count   ?? null,
      }
    });
  }
}

return result;

// Mode: Run Once for All Items
const mediaItems = $('mediaList').all();
const timeItems  = $('getTime').all();

// Build id ? { timestamp, children? } lookup
const timeMap = {};
for (const t of timeItems) {
  timeMap[t.json.id] = {
    timestamp: t.json.timestamp,
    children:  t.json.children ?? null,
  };
}

return mediaItems.map(item => ({
  json: {
    ...item.json,
    timestamp: timeMap[item.json.id]?.timestamp ?? null,
    children:  timeMap[item.json.id]?.children  ?? null,
  }
}));

