function getRanges(followers, ageHours, scaledM) {
  const age = ageHours < 48  ? 0.65
            : ageHours < 168 ? 0.90
            :                  1.00;
  const calc = key => ({
    red:    Math.round(followers * scaledM[key][0] * age),
    yellow: Math.round(followers * scaledM[key][1] * age),
  });
  return {
    Views: calc('Views'), Reach: calc('Reach'), Interactions: calc('Interactions'),
    Likes: calc('Likes'), Comments: calc('Comments'), Saves: calc('Saves'), Shares: calc('Shares'),
  };
}

// ?? Two-axis status helpers ???????????????????????????????????????????????????
// Axis 1: reach_tier = floor(log10(reach)), capped 0-3
function reachTier(reach) {
  if (reach < 1) return 0;
  return Math.min(3, Math.floor(Math.log10(reach)));
}
// reach_tier x quality_tier -> status
const STATUS_MATRIX = {
  3: { HIGH: 'Excellent', MEDIUM: 'Good',    LOW: 'Average' },
  2: { HIGH: 'Good',      MEDIUM: 'Average', LOW: 'Average' },
  1: { HIGH: 'Niche',     MEDIUM: 'Weak',    LOW: 'Dead'    },
  0: { HIGH: 'Dead',      MEDIUM: 'Dead',    LOW: 'Dead'    },
};

// ?? Status functions ??????????????????????????????????????????????????????????
// r and ft are still received so the call sites stay unchanged; the two-axis
// logic does not read them. Only the body of each function changed.
function getStatusCarousel(ageDays, engRateReach, rewatchRatio, commentLikeRatio, Comments, Shares, Reach, Interactions, Saved, r, ft) {
  //if (ageDays < 2)               return 'Weak';   // <48h, still building
  if (Reach < 10 && ageDays > 3) return 'Dead';    // nobody saw it

  const replay = rewatchRatio;                      // views / reach
  const engage = engRateReach;                      // interactions / reach
  const saving = Reach > 0 ? Saved / Reach : 0;     // saves / reach

  let score = 0;                                    // quality score, max 8
  if      (replay >= 2.0) score += 3;
  else if (replay >= 1.5) score += 2;
  else if (replay >= 1.2) score += 1;
  if      (engage >= 0.15) score += 3;
  else if (engage >= 0.08) score += 2;
  else if (engage >= 0.03) score += 1;
  if      (saving >= 0.04)  score += 2;
  else if (saving >= 0.015) score += 1;

  const qTier = score >= 5 ? 'HIGH' : score >= 3 ? 'MEDIUM' : 'LOW';
  return STATUS_MATRIX[reachTier(Reach)][qTier];
}

function getStatusReel(ageDays, engRateReach, rewatchRatio, commentLikeRatio, skipRate, Comments, Shares, Reach, Saved, r, ft, avgWatchSec) {
  //if (ageDays < 2)               return 'Weak';   // <48h, still building
  if (Reach < 10 && ageDays > 3) return 'Dead';    // nobody saw it

  const replay = rewatchRatio;                      // views / reach
  const engage = engRateReach;                      // interactions / reach
  const saving = Reach > 0 ? Saved / Reach : 0;     // saves / reach

  let score = 0;                                    // quality score, max 12
  if (skipRate !== null) {
    if      (skipRate < 0.35)  score += 3;
    else if (skipRate < 0.55)  score += 2;
    else if (skipRate <= 0.70) score += 1;
    else if (replay >= 1.5)    score += 1;          // >70% skip but watchers rewatch
  }
  if      (replay >= 2.0) score += 3;
  else if (replay >= 1.5) score += 2;
  else if (replay >= 1.2) score += 1;
  if      (engage >= 0.15) score += 3;
  else if (engage >= 0.08) score += 2;
  else if (engage >= 0.03) score += 1;
  if      (saving >= 0.04)  score += 2;
  else if (saving >= 0.015) score += 1;
  if (avgWatchSec != null && avgWatchSec >= 8) score += 1;

  const qTier = score >= 8 ? 'HIGH' : score >= 4 ? 'MEDIUM' : 'LOW';
  return STATUS_MATRIX[reachTier(Reach)][qTier];
}

function getStatusPost(ageDays, engRateReach, rewatchRatio, commentLikeRatio, Comments, Shares, Reach, Likes, Saved, r, ft) {
