// ?? Status functions ??????????????????????????????????????????????????????????
function getStatusCarousel(ageDays, engRateReach, rewatchRatio, commentLikeRatio, Comments, Shares, Reach, Interactions, Saved, r, ft) {
  let watchFlags = 0, excellentFlags = 0;
  const erA = ageDays < 5 ? 0.05 : ageDays < 10 ? 0.06 : ageDays < 21 ? 0.07 : 0.08;
  if (engRateReach < erA)                                      return 'Archive';
  if (ageDays >= 10 && r && Reach < r.Reach.red)               return 'Archive';
  if (ageDays >= 21 && r && Interactions < r.Interactions.red) return 'Archive';
  const erW = ageDays < 3 ? 0.07 : ageDays < 5 ? 0.09 : ageDays < 10 ? 0.11 : ageDays < 21 ? 0.13 : 0.15;
  if      (engRateReach < erW)  watchFlags++;
  else if (engRateReach > 0.18) excellentFlags++;
  const rwW = ageDays < 5 ? 1.05 : ageDays < 10 ? 1.08 : 1.10;
  if      (rewatchRatio < rwW)  watchFlags++;
  else if (rewatchRatio > 1.20) excellentFlags++;
  if      (Comments < 3)            watchFlags++;
  else if (commentLikeRatio > 0.30) excellentFlags++;
  else if (commentLikeRatio < 0.10) watchFlags++;
  else                              excellentFlags++;
  if      (Shares === 0) watchFlags++;
  else if (Shares >= 2)  excellentFlags++;
  let countWatch = 0, countExcellent = 0;
  if (r) {
    if      (Reach < r.Reach.yellow)               countWatch++;
    else if (Reach > r.Reach.yellow)               countExcellent++;
    if      (Interactions < r.Interactions.yellow) countWatch++;
    else if (Interactions > r.Interactions.yellow) countExcellent++;
    if (Saved > r.Saves.yellow)                    countExcellent++;
  }
  if (countWatch > 0) watchFlags++;
  excellentFlags += countExcellent;
  const watchNeeded = ageDays < 3 ? 3 : 2;
  if (watchFlags >= watchNeeded)                                             return 'Watch';
  if (watchFlags === 0 && Comments >= 3 &&
     (excellentFlags >= 4 || (excellentFlags >= 3 && engRateReach > 0.22))) return 'Excellent';
  if (watchFlags === 0 && engRateReach >= ft.EngagementVsReach_Yellow)      return 'Good';
  if (watchFlags === 1)                                                      return 'Average';
  return 'Watch';
}

function getStatusReel(ageDays, engRateReach, rewatchRatio, commentLikeRatio, skipRate, Comments, Shares, Reach, Saved, r, ft) {
  let watchFlags = 0, excellentFlags = 0;
  if (skipRate !== null) {
    if      (skipRate > 0.70) return 'Archive';
    else if (skipRate > 0.60) watchFlags++;
    else                      excellentFlags++;
  }
  const erA = ageDays < 7  ? 0.030 : ageDays < 14 ? 0.040 : ageDays < 30 ? 0.045 : 0.050;
  if (engRateReach < erA)                        return 'Archive';
  if (ageDays >= 14 && r && Reach < r.Reach.red) return 'Archive';
  const erW = ageDays < 3 ? 0.050 : ageDays < 7 ? 0.060 : ageDays < 14 ? 0.070 : 0.080;
  if      (engRateReach < erW)  watchFlags++;
  else if (engRateReach > 0.15) excellentFlags++;
  const rwA = ageDays < 7 ? 1.01 : ageDays < 14 ? 1.03 : 1.05;
  const rwW = ageDays < 7 ? 1.05 : ageDays < 14 ? 1.08 : 1.10;
  if      (rewatchRatio < rwA)  return 'Archive';
  else if (rewatchRatio < rwW)  watchFlags++;
  else if (rewatchRatio > 1.40) excellentFlags++;
  if      (Comments < 3)            watchFlags++;
  else if (commentLikeRatio > 0.30) excellentFlags++;
  else if (commentLikeRatio < 0.10) watchFlags++;
  else                              excellentFlags++;
  if      (Shares === 0) watchFlags++;
  else if (Shares >= 2)  excellentFlags++;
  let countWatch = 0, countExcellent = 0;
  if (r) {
    if      (Reach < r.Reach.yellow) countWatch++;
    else if (Reach > r.Reach.yellow) countExcellent++;
    if (Saved > r.Saves.yellow)      countExcellent++;
  }
  if (countWatch > 0) watchFlags++;
  excellentFlags += countExcellent;
  const watchNeeded = ageDays < 3 ? 3 : 2;
  if (watchFlags >= watchNeeded)                                             return 'Watch';
