// Axis 1: reach_tier = floor(log10(reach)), capped 0-3
function reachTier(reach) {
  if (reach < 1) return 0;
  return Math.min(3, Math.floor(Math.log10(reach)));
}
// reach_tier x quality_tier -> status
const STATUS_MATRIX = {
  3: { HIGH: 'Excellent', MEDIUM: 'Good',    LOW: 'Average' },
  2: { HIGH: 'Good',      MEDIUM: 'Average', LOW: 'Average' },
  1: { HIGH: 'Niche',     MEDIUM: 'Weak',    LOW: 'Dead'    },
  0: { HIGH: 'Dead',      MEDIUM: 'Dead',    LOW: 'Dead'    },
};

// ?? Status functions ??????????????????????????????????????????????????????????
// r and ft are still received so the call sites stay unchanged; the two-axis
