// ?? Main ??????????????????????????????????????????????????????????????????????
return $input.all().map(item => {
  const mediaId = item.json.data[0].id.split('/')[0];  // ? extract from metric entry
  const ctx     = switchMap[mediaId];
  if (!ctx) throw new Error(`No Switch context for id: ${mediaId}`);
  const mediaType = ctx.media_type;
  const cfg       = CONFIG[mediaType];
  if (!cfg) throw new Error(`Unknown media_type: ${mediaType}`);
  const { scaledM, ft, type: Type } = cfg;
  const girlName  = ctx.name;
  const Girl      = girlName.charAt(0).toUpperCase() + girlName.slice(1);
  const followers = ctx.followers_count;
  const follows   = ctx.follows_count;
  const postedAt  = ctx.timestamp || null;
  // ?? Metrics block ?????????????????????????????????????????????????????????
  const block = item.json.data;
  const m     = {};
  for (const entry of block) {
    m[entry.name] = entry.values[0]?.value ?? null;
  }
 // const mediaId           = item.json.id || block[0]?.id?.split('/')[0] || 'unknown';
  const Views             = m.views              ?? 0;
  const Reach             = m.reach              ?? 0;
  const Likes             = m.likes              ?? 0;
  const Comments          = m.comments           ?? 0;
  const Shares            = m.shares             ?? 0;
  const Saved             = m.saved              ?? 0;
  const totalInteractions = m.total_interactions ?? 0;
  const avgWatchTimeMs   = m.ig_reels_avg_watch_time        ?? 0;
  const totalWatchTimeMs = m.ig_reels_video_view_total_time ?? 0;
  const skipRate         = m.reels_skip_rate != null ? m.reels_skip_rate / 100 : null;
  const SlideCount = mediaType === 'CAROUSEL_ALBUM' ? (ctx.children?.data?.length ?? null) : null;
  const postedAtFormatted = postedAt
    ? DateTime.fromISO(postedAt).plus({hours: 14}).toFormat('dd/MM/yyyy HH:mm')
    : null;
  const ageHours = postedAt
    ? +DateTime.now().diff(DateTime.fromISO(postedAt), 'hours').hours.toFixed(1)
    : null;
  const ageDays  = ageHours != null ? +(ageHours / 24).toFixed(1) : null;
  const r = ageHours != null ? getRanges(followers, ageHours, scaledM) : null;
  const engRateReach     = Reach     > 0 ? +((totalInteractions / Reach)    ).toFixed(2) : 0;
  const engRateFollowers = followers > 0 ? +((totalInteractions / followers) ).toFixed(2) : 0;
  const rewatchRatio     = Reach     > 0 ? +(Views / Reach                   ).toFixed(2) : 0;
  const commentLikeRatio = Likes     > 0 ? +(Comments / Likes                ).toFixed(2) : 0;
  const reachRate        = followers > 0 ? +((Reach / followers)             ).toFixed(2) : 0;
  const avgWatchTimeSec   = mediaType === 'VIDEO' ? +(avgWatchTimeMs / 1000).toFixed(2) : null;
  const totalWatchTimeSec = mediaType === 'VIDEO' ? Math.floor(totalWatchTimeMs / 1000) : null;
  const totalWatchTimeMin = totalWatchTimeSec != null
    ? `${Math.floor(totalWatchTimeSec / 60)}m ${totalWatchTimeSec % 60}s`
    : null;
  let Status = 'Unknown';
  if (ageDays != null) {
    if      (mediaType === 'CAROUSEL_ALBUM')
      Status = getStatusCarousel(ageDays, engRateReach, rewatchRatio, commentLikeRatio, Comments, Shares, Reach, totalInteractions, Saved, r, ft);
    else if (mediaType === 'VIDEO')
      Status = getStatusReel(ageDays, engRateReach, rewatchRatio, commentLikeRatio, skipRate, Comments, Shares, Reach, Saved, r, ft);
    else if (mediaType === 'IMAGE')
      Status = getStatusPost(ageDays, engRateReach, rewatchRatio, commentLikeRatio, Comments, Shares, Reach, Likes, Saved, r, ft);
  }

  return {
    json: {
      Id:                           mediaId,
      Time:                         postedAtFormatted,
      Girl,
      Followers:                    followers,
      Following:                    follows,
      Type,
      AgeHours:                     ageHours,
      AgeDays:                      ageDays,
      Views, Reach, Interactions:   totalInteractions,
      Likes, Comments, Saved, Shares,
      WatchTime_AVG:                avgWatchTimeSec,
      WatchTime_Total:              totalWatchTimeMin,
      SkipRate:                     mediaType === 'VIDEO' ? skipRate : null,
      SlideCount,
      EngagementVsReach:            engRateReach,
      EngagementVsfollowers:        engRateFollowers,
      Rewatch:                      rewatchRatio,
      CommentVsLike:                commentLikeRatio,
      ReachVsFollowers:             reachRate,
      Status,
      Views_Red:                    r ? r.Views.red           : null,
      Views_Yellow:                 r ? r.Views.yellow        : null,
      Reach_Red:                    r ? r.Reach.red           : null,
      Reach_Yellow:                 r ? r.Reach.yellow        : null,
      Interactions_Red:             r ? r.Interactions.red    : null,
      Interactions_Yellow:          r ? r.Interactions.yellow : null,
      Likes_Red:                    r ? r.Likes.red           : null,
      Likes_Yellow:                 r ? r.Likes.yellow        : null,
      Comments_Red:                 r ? r.Comments.red        : null,
      Comments_Yellow:              r ? r.Comments.yellow     : null,
      Saves_Red:                    r ? r.Saves.red           : null,
      Saves_Yellow:                 r ? r.Saves.yellow        : null,
      Shares_Red:                   r ? r.Shares.red          : null,
      Shares_Yellow:                r ? r.Shares.yellow       : null,
      EngagementVsReach_Red:        ft.EngagementVsReach_Red,
      EngagementVsReach_Yellow:     ft.EngagementVsReach_Yellow,
      Rewatch_Red:                  ft.Rewatch_Red,
      Rewatch_Yellow:               ft.Rewatch_Yellow,
      ReachVsFollowers_Red:         ft.ReachVsFollowers_Red,
      ReachVsFollowers_Yellow:      ft.ReachVsFollowers_Yellow,
      EngagementVsFollowers_Red:    ut.EngagementVsFollowers_Red,
      EngagementVsFollowers_Yellow: ut.EngagementVsFollowers_Yellow,
      CommentVsLike_Red:            ut.CommentVsLike_Red,
      CommentVsLike_Yellow:         ut.CommentVsLike_Yellow,
    }
  };
});
